SELECT review_count
FROM review_statistics
WHERE department_id = (SELECT department_id FROM departments WHERE department_name = 'Operations');

SELECT category_name, description
FROM review_categories
WHERE category_id = 0;

SELECT COUNT(review_id) AS review_count
FROM review_category_mapping
WHERE category_id = 1;

SELECT department_id, SUM(review_count) AS total_reviews
FROM review_statistics
GROUP BY department_id;
